import torch
import torch.nn as nn

class PatchEmbedding(nn.Module):
    def __init__(self, img_size, patch_size, in_channels, embed_dim):
        super().__init__()
        self.proj = nn.Conv2d(in_channels, embed_dim, kernel_size=patch_size, stride=patch_size)

    def forward(self, x):
        x = self.proj(x)  # (B, embed_dim, H/patch_size, W/patch_size)
        x = x.flatten(2).transpose(1, 2)  # (B, num_patches, embed_dim)
        return x

def interpolate_weights(original_state_dict, finetuned_state_dict, alpha):
    interpolated_state_dict = {}
    for key in original_state_dict.keys():
        interpolated_state_dict[key] = (1 - alpha) * original_state_dict[key] + alpha * finetuned_state_dict[key]
    return interpolated_state_dict

import random

def fuzz_words(words):
    return [''.join(c + random.choice('!@#$%^&*()') for c in word) for word in words]

def count_setosa_small_petals(filepath):
    import csv
    count = 0
    with open(filepath, newline='') as f:
        reader = csv.DictReader(f)
        for row in reader:
            if row['Name'] == 'Iris-setosa' and float(row['PetalLength']) < 1.5:
                count += 1
    return count

